import React from "react";

export default function WeatherOverlay({ condition, isDay }) {
  // Ensure condition is always a lowercase string (or fallback to 'clear')
  const weather = (condition || "clear").toLowerCase();

  let overlay = "/overlays/Sun-Weather-App.gif"; // default

  if (weather.includes("rain")) {
    overlay = isDay ? "/overlays/rain.gif" : "/overlays/rainNight.gif";
  } else if (weather.includes("snow")) {
    overlay = "/overlays/snow.gif";
  } else if (weather.includes("thunder")) {
    overlay = "/overlays/thunderstorm.gif";
  } else if (weather.includes("wind")) {
    overlay = "/overlays/Windy-Weather-App.gif";
  } else if (weather.includes("cloud")) {
    overlay = isDay ? "/overlays/PCday.gif" : "/overlays/PCnight.gif";
  } else {
    overlay = isDay ? "/overlays/sunset.gif" : "/overlays/night.gif";
  }

  return (
    <div className="absolute inset-0 z-0 overflow-hidden">
      <img
        src={overlay}
        alt="Weather overlay"
        className="w-full h-full object-cover opacity-80 pointer-events-none"
      />
    </div>
  );
}
